INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (1, 'The good physician treats the disease; the great physician treats the patient who has the disease.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','service','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (2, 'Medicine is a science of uncertainty and an art of probability.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','humility'], 'clinical_wisdom', 'reflective', ARRAY['dashboard_daily_quote','share_card','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (3, 'The practice of medicine is an art, not a trade; a calling, not a business; a calling in which your heart will be exercised equally with your head.', 'The practice of medicine is an art, not a trade; a calling, not a business.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['medicine','ethics','service'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (4, 'Observe, record, tabulate, communicate.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','mastery','truth'], 'clinical_wisdom', 'disciplined', ARRAY['dashboard_daily_quote','study_motivation','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (5, 'To study the phenomena of disease without books is to sail an uncharted sea, while to study books without patients is not to go to sea at all.', 'To study disease without books is to sail an uncharted sea.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['learning','medicine','mastery'], 'teaching', 'visionary', ARRAY['study_motivation','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (6, 'The best preparation for tomorrow is to do today''s work superbly well.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','excellence','focus'], 'excellence', 'disciplined', ARRAY['dashboard_daily_quote','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (7, 'Soap, water, and common sense are the best disinfectants.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','discipline'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','teaching_rounds','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (8, 'One of the first duties of the physician is to educate the masses not to take medicine.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','ethics','truth'], 'patient_care', 'reflective', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (9, 'Variability is the law of life, and as no two faces are the same, so no two bodies are alike, and no two individuals react alike and behave alike under the abnormal conditions which we know as disease.', 'Variability is the law of life.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','humility'], 'clinical_wisdom', 'reflective', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (10, 'The desire to take medicine is perhaps the greatest feature which distinguishes man from animals.', NULL, 'William Osler', '1849–1919', 'Science and Immortality', 'high', ARRAY['medicine','philosophy','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (11, 'He who studies medicine without books sails an uncharted sea, but he who studies medicine without patients does not go to sea at all.', NULL, 'William Osler', '1849–1919', 'Books and Men', 'high', ARRAY['learning','medicine','mastery'], 'teaching', 'visionary', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (12, 'The value of experience is not in seeing much, but in seeing wisely.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['mastery','truth','learning'], 'clinical_wisdom', 'reflective', ARRAY['post_op_reflection','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (13, 'In the fight which we have to wage incessantly against ignorance and quackery among the masses and follies of all sorts among the classes, diagnosis, not drugging, is our chief weapon of offence.', 'Diagnosis, not drugging, is our chief weapon of offence.', 'William Osler', '1849–1919', 'Chauvinism in Medicine', 'high', ARRAY['medicine','truth','courage'], 'clinical_wisdom', 'relentless', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (14, 'The young doctor should look about early for an avocation, a pastime, that will take him away from patients, pills, and potions.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','philosophy','humility'], 'reflection', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (15, 'Gentlemen, I have a confession to make. Half of what we have taught you is in error, and furthermore we cannot tell you which half it is.', 'Half of what we have taught you is in error.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','truth','learning'], 'teaching', 'reflective', ARRAY['teaching_rounds','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (16, 'The very first step towards success in any occupation is to become interested in it.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['excellence','discipline','focus'], 'excellence', 'visionary', ARRAY['onboarding','study_motivation','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (17, 'Live neither in the past nor in the future, but let each day''s work absorb your entire energies, and satisfy your widest ambition.', 'Let each day''s work absorb your entire energies.', 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['focus','discipline','excellence'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (18, 'There is a form of laughter that is born out of the recognition of the incongruities of life, a laughter too deep for tears.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','philosophy','humility'], 'reflection', 'reflective', ARRAY['post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (19, 'A physician who treats himself has a fool for a patient.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (20, 'No human being is constituted to know the truth, the whole truth, and nothing but the truth; and even the best of men must be content with fragments, with partial glimpses, never the full fruition.', 'Even the best of men must be content with fragments, with partial glimpses.', 'William Osler', '1849–1919', 'The Student Life', 'high', ARRAY['humility','truth','philosophy'], 'philosophy', 'reflective', ARRAY['post_op_reflection','share_card','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (21, 'Act the part and you will become the part.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','mastery','focus'], 'surgeon_mindset', 'elite', ARRAY['pre_op_mindset','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (22, 'The trained nurse has become one of the great blessings of humanity, taking a place beside the physician and the priest.', NULL, 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['service','medicine','virtue'], 'patient_care', 'compassionate', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (23, 'It is much simpler to buy books than to read them and easier to read them than to absorb their contents.', NULL, 'William Osler', '1849–1919', 'Books and Men', 'high', ARRAY['learning','humility','discipline'], 'teaching', 'reflective', ARRAY['study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (24, 'We are here to add what we can to life, not to get what we can from life.', NULL, 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['service','ethics','virtue'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (25, 'The philosophies of one age have become the absurdities of the next, and the foolishness of yesterday has become the wisdom of tomorrow.', 'The foolishness of yesterday has become the wisdom of tomorrow.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['philosophy','truth','humility'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (26, 'In science the credit goes to the man who convinces the world, not to the man to whom the idea first occurs.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['truth','leadership','excellence'], 'leadership', 'stoic', ARRAY['leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (27, 'To have a group of cloistered clinicians away from the broad current of professional life would be bad for teacher and worse for student.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','medicine','leadership'], 'teaching', 'reflective', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (28, 'Humanity has but three great enemies: fever, famine, and war; of these by far the greatest, by far the most terrible, is fever.', 'Humanity''s three great enemies: fever, famine, and war.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','courage'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (29, 'To have striven, to have made the effort, to have been true to certain ideals — this alone is worth the struggle.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','virtue','excellence'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (30, 'Start at once a bedside library and spend the last half hour of the day in communion with the saints of humanity.', NULL, 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['learning','discipline','philosophy'], 'teaching', 'calm', ARRAY['study_motivation','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (31, 'Medicine is learned by the bedside and not in the classroom.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','medicine','mastery'], 'teaching', 'disciplined', ARRAY['teaching_rounds','study_motivation','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (32, 'The natural man has only two primal passions: to get and to beget.', NULL, 'William Osler', '1849–1919', 'Science and Immortality', 'high', ARRAY['philosophy','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (33, 'Throw all the beer and spirits into the Irish Channel, the English Channel, and the North Sea for a year, and people in England would be infinitely better.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','ethics'], 'clinical_wisdom', 'reflective', ARRAY['share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (34, 'There is no more difficult art to acquire than the art of observation.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['mastery','discipline','learning'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds','study_motivation','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (35, 'Look wise, say nothing, and grunt. Speech was given to conceal thought.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','discipline','truth'], 'clinical_wisdom', 'calm', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (36, 'The greater the ignorance the greater the dogmatism.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','truth','learning'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (37, 'Courage and cheerfulness will not only carry you over the rough places in life, but will enable you to bring comfort and help to the weak-hearted.', 'Courage and cheerfulness will carry you over the rough places in life.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','courage','service'], 'resilience', 'compassionate', ARRAY['post_op_reflection','onboarding','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (38, 'It is much more important to know what sort of a patient has a disease than what sort of a disease a patient has.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','service','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (39, 'The failures of to-day may prove to be the successes of to-morrow.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','courage','truth'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (40, 'Acquire the art of detachment, the virtue of method, and the quality of thoroughness, but above all the grace of humility.', 'Acquire detachment, method, thoroughness, but above all humility.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['humility','discipline','mastery'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (41, 'Nothing will sustain you more potently than the power to recognize in your humdrum routine the true poetry of life.', NULL, 'William Osler', '1849–1919', 'The Student Life', 'high', ARRAY['resilience','philosophy','focus'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (42, 'The motto of each of you as you depart from its threshold should be the old one — work, work, work.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','excellence','focus'], 'excellence', 'relentless', ARRAY['study_motivation','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (43, 'The best doctor is the one you run to and can''t find.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['medicine','humility','truth'], 'clinical_wisdom', 'calm', ARRAY['share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (44, 'Imperturbability means coolness and presence of mind under all circumstances, calmness amid storm, clearness of judgment in moments of grave peril.', 'Imperturbability means coolness and presence of mind under all circumstances.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['discipline','focus','courage'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (45, 'A man cannot become a competent surgeon without the full knowledge of human anatomy and physiology, and the physician without physiology and chemistry flounders along in an aimless fashion.', 'A surgeon cannot be competent without full knowledge of anatomy and physiology.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['mastery','medicine','learning'], 'clinical_wisdom', 'disciplined', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (46, 'The art of the practice of medicine is to be learned only by experience; ''tis not an inheritance; it cannot be revealed.', 'The art of medicine is learned only by experience.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['mastery','learning','medicine'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (47, 'Care more for the individual patient than for the special features of the disease.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['service','medicine','ethics'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','teaching_rounds','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (48, 'The student who is bubbling over with high spirits and good health can ill appreciate the struggles and the miseries of the sick.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','service','truth'], 'patient_care', 'reflective', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (49, 'Tact is a quality not to be despised. It is the saving grace of many a situation.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['virtue','humility','leadership'], 'leadership', 'calm', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (50, 'Work is the master word in medicine.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','excellence','mastery'], 'excellence', 'relentless', ARRAY['study_motivation','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (51, 'The student begins with the patient, continues with the patient, and ends his studies with the patient.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','medicine','service'], 'teaching', 'disciplined', ARRAY['onboarding','teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (52, 'No bubble is so iridescent or floats longer than that blown by the successful teacher.', NULL, 'William Osler', '1849–1919', 'Teacher and Student', 'high', ARRAY['leadership','learning','excellence'], 'teaching', 'visionary', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (53, 'What is patience but an equanimity which enables you to rise superior to the trials of life.', NULL, 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['resilience','discipline','virtue'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (54, 'Common sense in matters medical is rare, and is usually in inverse ratio to the degree of education.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','truth','medicine'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (55, 'In the mortality bills, pneumonia is an easy second to tuberculosis; indeed, in many cities the death-rate is now higher, and it has become, to use the phrase of Bunyan, ''the captain of the men of death.''', 'Pneumonia has become the captain of the men of death.', 'William Osler', '1849–1919', 'The Principles and Practice of Medicine', 'high', ARRAY['medicine','truth'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (56, 'There is no disease more conducive to clinical humility than aneurysm of the aorta.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (57, 'The uselessness of drugs is a knowledge which has been more slowly acquired and which is less generally available.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','humility'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (58, 'To wrest from nature the secrets which have perplexed philosophers in all ages, to track to their sources the causes of disease — these are our ambitions.', 'To wrest from nature the secrets which have perplexed philosophers — these are our ambitions.', 'William Osler', '1849–1919', 'Chauvinism in Medicine', 'high', ARRAY['mastery','truth','courage'], 'excellence', 'visionary', ARRAY['founder_mode','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (59, 'It is a common error to think that the more a doctor does, the better.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'calm', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (60, 'Throw away all ambition beyond that of doing the day''s work well.', NULL, 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['focus','discipline','humility'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (61, 'The man who does not know the other side of his case, knows little of his own.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','truth','learning'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (62, 'There is no more potent antidote to the corroding influence of mammon than the cultivation of the humanities.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['philosophy','virtue','learning'], 'reflection', 'reflective', ARRAY['study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (63, 'Take the sum of human achievement in action, in science, in art, in literature — subtract the work of the men above forty, and while we should miss great treasures, even priceless treasures, we would practically be where we are today.', 'Subtract the work of men above forty and we would practically be where we are today.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['truth','philosophy','courage'], 'reflection', 'reflective', ARRAY['share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (64, 'Begin at once to live, and count each separate day as a separate life.', NULL, 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['focus','discipline','excellence'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (65, 'Observe how the doctor treats his servants, his dog, his cat; if he is kind to these dumb creatures, he will be kind to you.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['ethics','virtue','service'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (66, 'A library is a hospital for the mind.', NULL, 'William Osler', '1849–1919', 'Books and Men', 'high', ARRAY['learning','philosophy','medicine'], 'teaching', 'visionary', ARRAY['study_motivation','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (67, 'The older I grow, the more I am convinced that what we call diseases are but symptoms, and that real understanding lies in comprehending the conditions which produce them.', 'What we call diseases are but symptoms.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','mastery'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (68, 'The young physician starts life with twenty drugs for each disease, and the old physician ends life with one drug for twenty diseases.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['mastery','humility','medicine'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (69, 'Undoubtedly the student tries to learn too much, and we teachers try to teach him too much — neither, perhaps, with great success.', NULL, 'William Osler', '1849–1919', 'The Student Life', 'high', ARRAY['learning','humility','truth'], 'teaching', 'reflective', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (70, 'To confess ignorance is often wiser than to beat about the bush with a hypothetical diagnosis.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','truth','ethics'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (71, 'The day of the physician as a mere drug giver is done. He must be something more. He must be an adviser, a teacher, and a friend.', 'The physician must be an adviser, a teacher, and a friend.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['service','medicine','ethics'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (72, 'One finger in the throat and one in the rectum makes a good diagnostician.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','discipline','truth'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (73, 'The first qualification for a physician is hopefulness.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','virtue','service'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (74, 'Each one of you will find in the exercise of your profession opposition, difficulties, hardships, but let me assure you that these are blessings in disguise.', 'Opposition, difficulties, hardships — these are blessings in disguise.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','courage','virtue'], 'resilience', 'stoic', ARRAY['post_op_reflection','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (75, 'In seeking absolute truth we aim at the unattainable and must be content with broken portions.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['truth','humility','philosophy'], 'philosophy', 'reflective', ARRAY['post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (76, 'Specialism is not, however, without many disadvantages. A man may be so intent upon studying the teeth that he overlooks the head.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','humility'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (77, 'The good old days, so dear to the hearts of our grandfathers, were among the worst man has had to endure.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['truth','philosophy','courage'], 'philosophy', 'reflective', ARRAY['share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (78, 'The extraordinary development of modern science may be her undoing. Specialism, now a necessity, has fragmented the specialties themselves in a way that makes the outlook hazardous.', 'Specialism, now a necessity, has fragmented the specialties themselves.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','leadership'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (79, 'Let no man be so foolish as to think that he has exhausted any subject.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','learning','truth'], 'reflection', 'stoic', ARRAY['study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (80, 'The internist knows everything and does nothing. The surgeon knows nothing and does everything. The pathologist knows everything and does everything — but too late.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['medicine','humility','truth'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (81, 'We are here not to get all we can out of life for ourselves, but to try to make the lives of others happier.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['service','ethics','virtue'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (82, 'To it, more than to anything else, I owe whatever success I have had — to this power of settling down to the day''s work and trying to do it well to the best of one''s ability.', 'Settle down to the day''s work and try to do it well.', 'William Osler', '1849–1919', 'A Way of Life', 'high', ARRAY['discipline','excellence','focus'], 'excellence', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (83, 'It is one of the greatest blessings that so many women are so willing to engage in the work of nursing the sick.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['service','medicine','virtue'], 'patient_care', 'compassionate', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (84, 'Faith in the gods or saints cures one, faith in little pills another, hypnotic suggestion a third, faith in a plain common doctor a fourth.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['medicine','truth','philosophy'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (85, 'Take things always by their smooth handle.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['resilience','discipline','focus'], 'surgeon_mindset', 'calm', ARRAY['pre_op_mindset','push_notification'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (86, 'System and method should be the very soul of clinical instruction.', NULL, 'William Osler', '1849–1919', 'Teacher and Student', 'high', ARRAY['discipline','mastery','learning'], 'teaching', 'disciplined', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (87, 'It is the curse of humanity that it learns to tolerate even the most horrible situations by habituation.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['truth','ethics','philosophy'], 'philosophy', 'reflective', ARRAY['post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (88, 'No teaching without a patient for a text, and the best teaching is that taught by the patient himself.', NULL, 'William Osler', '1849–1919', 'The Student Life', 'high', ARRAY['learning','medicine','mastery'], 'teaching', 'disciplined', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (89, 'Look back to the great names of medicine — they were all well-read men. Do not be content with the ordinary.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','excellence','mastery'], 'excellence', 'elite', ARRAY['study_motivation','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (90, 'Things cannot always go your way. Learn to accept in silence the minor aggravations, cultivate the gift of taciturnity.', 'Learn to accept in silence the minor aggravations.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['resilience','discipline','virtue'], 'resilience', 'stoic', ARRAY['post_op_reflection','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (91, 'The hospital is the only proper college in which to rear a true disciple of Aesculapius.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','medicine','mastery'], 'teaching', 'disciplined', ARRAY['onboarding','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (92, 'The most dangerous foe to progress is not ignorance but the illusion of knowledge.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['humility','truth','learning'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','share_card','study_motivation'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (93, 'A man must have faith in himself, but humility enough to know when he is wrong.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['humility','courage','truth'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (94, 'By far the most dangerous foe we have to fight is apathy — indifference from whatever cause, not from a lack of knowledge, but from carelessness, from absorption in other pursuits.', 'The most dangerous foe we have to fight is apathy.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['discipline','courage','ethics'], 'leadership', 'relentless', ARRAY['leadership_prompt','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (95, 'Engrossed late and soon in professional cares, getting but little rest, and often burdened with a sense of responsibility, the physician needs above all things serenity of mind.', 'The physician needs above all things serenity of mind.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['resilience','focus','discipline'], 'surgeon_mindset', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (96, 'Method is the mother of memory.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['discipline','mastery','learning'], 'excellence', 'disciplined', ARRAY['study_motivation','push_notification'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (97, 'The teacher who is attempting to teach without inspiring the pupil with a desire to learn is hammering on cold iron.', NULL, 'William Osler', '1849–1919', NULL, 'medium', ARRAY['leadership','learning','excellence'], 'teaching', 'visionary', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (98, 'True happiness comes from having a purpose and building upon it day by day.', NULL, 'William Osler', '1849–1919', NULL, 'low', ARRAY['discipline','philosophy','virtue'], 'reflection', 'calm', ARRAY['dashboard_daily_quote','push_notification'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (99, 'The mission of a university is not to teach bread-winning, or to furnish teachers for the public schools, or to be a centre of polite learning. A university is not a mill, not a factory, but a centre of thought.', 'A university is not a mill, not a factory, but a centre of thought.', 'William Osler', '1849–1919', NULL, 'medium', ARRAY['learning','truth','philosophy'], 'teaching', 'visionary', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (100, 'The quest for righteousness is Oriental, the quest for knowledge is Occidental. The union of these two in a harmonious whole makes the perfect physician.', 'The union of righteousness and knowledge makes the perfect physician.', 'William Osler', '1849–1919', 'Aequanimitas', 'high', ARRAY['medicine','virtue','mastery'], 'philosophy', 'visionary', ARRAY['onboarding','share_card','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (101, 'First, do no harm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath (paraphrase)', 'medium', ARRAY['ethics','medicine','service'], 'patient_care', 'stoic', ARRAY['pre_op_mindset','onboarding','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (102, 'Healing is a matter of time, but it is sometimes also a matter of opportunity.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['medicine','mastery','focus'], 'clinical_wisdom', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (103, 'Wherever the art of medicine is loved, there is also a love of humanity.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['service','medicine','ethics'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (104, 'Life is short, and art long, opportunity fleeting, experience perilous, and decision difficult.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['mastery','truth','discipline'], 'clinical_wisdom', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (105, 'Let food be thy medicine and medicine be thy food.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['medicine','truth','discipline'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (106, 'There are in fact two things, science and opinion; the former begets knowledge, the latter ignorance.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Law', 'high', ARRAY['truth','learning','discipline'], 'teaching', 'stoic', ARRAY['study_motivation','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (107, 'Natural forces within us are the true healers of disease.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['medicine','truth','philosophy'], 'clinical_wisdom', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (108, 'Walking is man''s best medicine.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['medicine','discipline','truth'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (109, 'The physician must be able to tell the antecedents, know the present, and foretell the future.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['mastery','medicine','truth'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds','pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (110, 'Make a habit of two things: to help; or at least to do no harm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['ethics','service','medicine'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (111, 'To do nothing is sometimes a good remedy.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (112, 'A wise man should consider that health is the greatest of human blessings.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Regimen in Health', 'high', ARRAY['medicine','philosophy','truth'], 'patient_care', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (113, 'If we could give every individual the right amount of nourishment and exercise, not too little and not too much, we would have found the safest way to health.', 'The right amount of nourishment and exercise is the safest way to health.', 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['medicine','discipline','truth'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (114, 'The art is long, life is short, experience uncertain, and judgment difficult.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['mastery','humility','truth'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (115, 'Declare the past, diagnose the present, foretell the future.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['mastery','medicine','truth'], 'clinical_wisdom', 'disciplined', ARRAY['pre_op_mindset','teaching_rounds','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (116, 'Everything in excess is opposed to nature.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['discipline','truth','philosophy'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (117, 'Prayer indeed is good, but while calling on the gods a man should himself lend a hand.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Regimen', 'high', ARRAY['discipline','courage','truth'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (118, 'Science is the father of knowledge, but opinion breeds ignorance.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Law', 'high', ARRAY['truth','learning','discipline'], 'teaching', 'stoic', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (119, 'The chief virtue that language can have is clearness, and nothing detracts from it so much as the use of unfamiliar words.', NULL, 'Hippocrates', 'c. 460–370 BC', 'On the Art', 'high', ARRAY['truth','discipline','learning'], 'teaching', 'disciplined', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (120, 'Extreme remedies are very appropriate for extreme diseases.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','truth'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (121, 'It is more important to know what sort of person has a disease than to know what sort of disease a person has.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['service','medicine','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (122, 'Those diseases which medicines do not cure, iron cures; those which iron cannot cure, fire cures; and those which fire cannot cure, are to be reckoned wholly incurable.', 'Those diseases which medicines do not cure, iron cures; those which iron cannot cure, fire cures.', 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','truth'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (123, 'What drugs fail to cure, the knife cures. What the knife fails to cure, cautery cures. What cautery fails to cure must be considered incurable.', 'What drugs fail to cure, the knife cures.', 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','mastery'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (124, 'The patient must combat the disease along with the physician.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['service','medicine','resilience'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (125, 'Cure sometimes, treat often, comfort always.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['service','medicine','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','onboarding','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (126, 'From the brain, and from the brain only, arise our pleasures, joys, laughter, and jests, as well as our sorrows, pains, griefs, and tears.', 'From the brain only arise our pleasures, joys, sorrows, and tears.', 'Hippocrates', 'c. 460–370 BC', 'On the Sacred Disease', 'high', ARRAY['medicine','truth','philosophy'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (127, 'Keep a watch also on the faults of the patients, which often make them lie about the taking of things prescribed.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Decorum', 'high', ARRAY['truth','medicine','discipline'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (128, 'Men think epilepsy divine, merely because they do not understand it. We will one day understand what causes it, and then cease to call it divine.', 'Men think epilepsy divine merely because they do not understand it.', 'Hippocrates', 'c. 460–370 BC', 'On the Sacred Disease', 'high', ARRAY['truth','medicine','courage'], 'clinical_wisdom', 'visionary', ARRAY['teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (129, 'Desperate diseases need desperate remedies.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','mastery'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (130, 'I will follow that system of regimen which, according to my ability and judgment, I consider for the benefit of my patients.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath', 'high', ARRAY['ethics','service','medicine'], 'patient_care', 'disciplined', ARRAY['onboarding','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (131, 'Idleness and lack of occupation tend — nay are dragged — towards evil.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Decorum', 'high', ARRAY['discipline','virtue','truth'], 'surgeon_mindset', 'disciplined', ARRAY['study_motivation','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (132, 'Sleep and watchfulness, both of them, when immoderate, constitute disease.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['discipline','medicine','truth'], 'clinical_wisdom', 'stoic', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (133, 'What medicines do not heal, the lance will; what the lance does not heal, fire will.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','mastery'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (134, 'Sometimes give your services for nothing, calling to mind a previous benefaction or present satisfaction.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['service','ethics','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (135, 'Each disease has its own nature and arises from external causes.', NULL, 'Hippocrates', 'c. 460–370 BC', 'On the Sacred Disease', 'high', ARRAY['medicine','truth','learning'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (136, 'A physician without a knowledge of astrology has no right to call himself a physician.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'low', ARRAY['learning','truth','medicine'], 'clinical_wisdom', 'reflective', ARRAY['share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (137, 'Whenever a doctor cannot do good, he must be kept from doing harm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['ethics','medicine','humility'], 'patient_care', 'stoic', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (138, 'In diseases, look to the nature of the patient as much as to the disease itself.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['service','medicine','humility'], 'patient_care', 'compassionate', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (139, 'The physician must have at his command a certain ready wit, as dourness is repulsive both to the healthy and the sick.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Decorum', 'high', ARRAY['virtue','service','humility'], 'patient_care', 'calm', ARRAY['onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (140, 'Into whatsoever houses I enter, I will enter to help the sick, and I will abstain from all intentional wrong-doing and harm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath', 'high', ARRAY['ethics','service','medicine'], 'patient_care', 'disciplined', ARRAY['onboarding','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (141, 'In acute diseases it is not quite safe to prognosticate either death or recovery.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (142, 'Of several remedies, the physician should choose the least sensational.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['humility','discipline','medicine'], 'clinical_wisdom', 'calm', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (143, 'The physician treats, but nature heals.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['humility','medicine','truth'], 'clinical_wisdom', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (144, 'It is far more important to know what person the disease has than what disease the person has.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['service','medicine','humility'], 'patient_care', 'compassionate', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (145, 'As to diseases, make a habit of two things — to help, or at least not to harm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['ethics','service','medicine'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (146, 'Old people have fewer diseases than the young, but their diseases never leave them.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['medicine','truth','humility'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (147, 'Persons who are naturally very fat are apt to die earlier than those who are slender.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['medicine','truth','discipline'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (148, 'The soul is the same in all living creatures, although the body of each is different.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['philosophy','truth','humility'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (149, 'There is one common flow, one common breathing. All things are in sympathy.', NULL, 'Hippocrates', 'c. 460–370 BC', 'On Nutriment', 'high', ARRAY['philosophy','truth','medicine'], 'philosophy', 'calm', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (150, 'I will remember that I remain a member of society, with special obligations to all my fellow human beings, those sound of mind and body as well as the infirm.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath (modern)', 'medium', ARRAY['ethics','service','virtue'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (151, 'The most violent diseases require the most violent remedies.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','mastery'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (152, 'He who desires to practice surgery must go to war.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['courage','mastery','medicine'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (153, 'Many admire, few know.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['mastery','truth','humility'], 'excellence', 'elite', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (154, 'Rest as soon as there is pain is a great restorative in all disturbances of the body.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['medicine','discipline','truth'], 'clinical_wisdom', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (155, 'What cannot be cured by medicaments is cured by the knife, what the knife cannot cure is cured with the searing iron, and whatever this cannot cure must be considered incurable.', 'What medicaments cannot cure, the knife cures.', 'Hippocrates', 'c. 460–370 BC', 'Aphorisms', 'high', ARRAY['courage','medicine','mastery'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (156, 'Fatigue, food, drink, sleep, love — let all be moderate.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['discipline','truth','medicine'], 'clinical_wisdom', 'disciplined', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (157, 'The art consists in three things — the disease, the patient, and the physician.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Epidemics', 'high', ARRAY['medicine','truth','mastery'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (158, 'A physician who is a lover of wisdom is the equal of a god.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Decorum', 'high', ARRAY['mastery','philosophy','excellence'], 'philosophy', 'visionary', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (159, 'Leave nothing to chance, overlook nothing; combine contradictory observations and allow yourself enough time.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['discipline','mastery','truth'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (160, 'I will apply dietetic measures for the benefit of the sick according to my ability and judgment; I will keep them from harm and injustice.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath', 'high', ARRAY['ethics','service','medicine'], 'patient_care', 'disciplined', ARRAY['onboarding','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (161, 'Primum non nocere.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath (Latin paraphrase)', 'medium', ARRAY['ethics','medicine','humility'], 'patient_care', 'stoic', ARRAY['pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (162, 'Time is that wherein there is opportunity, and opportunity is that wherein there is no great time.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['focus','mastery','discipline'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (163, 'And I will not give a drug that is deadly to anyone if asked, nor will I suggest the way to such a counsel.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath', 'high', ARRAY['ethics','medicine','virtue'], 'patient_care', 'stoic', ARRAY['onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (164, 'All parts of the body which have a function, if used in moderation and exercised in labors in which each is accustomed, become thereby healthy, well developed, and age more slowly.', 'All parts of the body, if used in moderation and exercised, become healthy and age slowly.', 'Hippocrates', 'c. 460–370 BC', 'On Joints', 'high', ARRAY['discipline','medicine','truth'], 'clinical_wisdom', 'disciplined', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (165, 'Positive health requires a knowledge of man''s primary constitution and of the powers of various foods, both those natural to them and those resulting from human skill.', NULL, 'Hippocrates', 'c. 460–370 BC', 'On Ancient Medicine', 'high', ARRAY['learning','medicine','mastery'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (166, 'The physician must be experienced in many things, but assuredly also in rubbing.', NULL, 'Hippocrates', 'c. 460–370 BC', 'On Joints', 'high', ARRAY['mastery','medicine','discipline'], 'clinical_wisdom', 'disciplined', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (167, 'The body of man has in itself blood, phlegm, yellow bile, and black bile; these make up the nature of the body, and through these he feels pain or enjoys health.', 'The body has blood, phlegm, yellow bile, and black bile; through these comes pain or health.', 'Hippocrates', 'c. 460–370 BC', 'On the Nature of Man', 'high', ARRAY['medicine','truth','learning'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (168, 'Where there is love for mankind, there is love for the art of healing.', NULL, 'Hippocrates', 'c. 460–370 BC', 'Precepts', 'high', ARRAY['service','medicine','ethics'], 'patient_care', 'compassionate', ARRAY['onboarding','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (169, 'That which is used develops; that which is not used wastes away.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['discipline','mastery','truth'], 'excellence', 'disciplined', ARRAY['study_motivation','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (170, 'He who would become a surgeon should join the army and follow it.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['courage','mastery','discipline'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (171, 'Foolish the doctor who despises the knowledge acquired by the ancients.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['learning','humility','truth'], 'teaching', 'reflective', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (172, 'Sport is a preserver of health.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['medicine','discipline','truth'], 'clinical_wisdom', 'calm', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (173, 'If you are not your own doctor, you are a fool.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'low', ARRAY['discipline','truth','medicine'], 'clinical_wisdom', 'stoic', ARRAY['share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (174, 'Whenever two things and more occur together that the one is not the cause of the other.', NULL, 'Hippocrates', 'c. 460–370 BC', NULL, 'medium', ARRAY['truth','learning','mastery'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (175, 'What I may see or hear in the course of the treatment or even outside of the treatment in regard to the life of men, I will keep to myself.', NULL, 'Hippocrates', 'c. 460–370 BC', 'The Oath', 'high', ARRAY['ethics','virtue','service'], 'patient_care', 'disciplined', ARRAY['onboarding','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (176, 'The unexamined life is not worth living.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['philosophy','truth','humility'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (177, 'I know that I know nothing.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['humility','philosophy','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (178, 'True wisdom comes to each of us when we realize how little we understand about life, ourselves, and the world around us.', 'True wisdom comes when we realize how little we understand.', 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'medium', ARRAY['humility','philosophy','learning'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (179, 'The only true wisdom is in knowing you know nothing.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'medium', ARRAY['humility','philosophy','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (180, 'To find yourself, think for yourself.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','truth','courage'], 'reflection', 'stoic', ARRAY['dashboard_daily_quote','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (181, 'Be slow to fall into friendship, but when you are in, continue firm and constant.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['virtue','discipline','ethics'], 'leadership', 'disciplined', ARRAY['leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (182, 'An honest man is always a child.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['virtue','humility','truth'], 'philosophy', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (183, 'There is only one good, knowledge, and one evil, ignorance.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Protagoras', 'medium', ARRAY['learning','philosophy','truth'], 'philosophy', 'stoic', ARRAY['study_motivation','dashboard_daily_quote','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (184, 'I cannot teach anybody anything. I can only make them think.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','philosophy','humility'], 'teaching', 'reflective', ARRAY['teaching_rounds','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (185, 'Wonder is the beginning of wisdom.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Theaetetus', 'medium', ARRAY['learning','philosophy','humility'], 'philosophy', 'visionary', ARRAY['onboarding','study_motivation','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (186, 'Education is the kindling of a flame, not the filling of a vessel.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','excellence','philosophy'], 'teaching', 'visionary', ARRAY['teaching_rounds','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (187, 'By all means marry; if you get a good wife, you''ll become happy; if you get a bad one, you''ll become a philosopher.', 'Marry; a good wife makes you happy, a bad one makes you a philosopher.', 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','resilience','humility'], 'reflection', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (188, 'He who is not contented with what he has, would not be contented with what he would like to have.', NULL, 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'medium', ARRAY['discipline','virtue','humility'], 'reflection', 'stoic', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (189, 'Contentment is natural wealth, luxury is artificial poverty.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['discipline','virtue','philosophy'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (190, 'Death may be the greatest of all human blessings.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['courage','philosophy','resilience'], 'philosophy', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (191, 'No man has the right to be an amateur in the matter of physical training. It is a shame for a man to grow old without seeing the beauty and strength of which his body is capable.', 'It is a shame to grow old without seeing the strength your body is capable of.', 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'high', ARRAY['excellence','discipline','mastery'], 'excellence', 'relentless', ARRAY['pre_op_mindset','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (192, 'Employ your time in improving yourself by other men''s writings, so that you shall gain easily what others have labored hard for.', 'Improve yourself by other men''s writings.', 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','mastery','excellence'], 'teaching', 'disciplined', ARRAY['study_motivation','teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (193, 'The way to gain a good reputation is to endeavor to be what you desire to appear.', NULL, 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'medium', ARRAY['virtue','excellence','ethics'], 'excellence', 'disciplined', ARRAY['leadership_prompt','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (194, 'Let him that would move the world first move himself.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['leadership','discipline','excellence'], 'leadership', 'stoic', ARRAY['leadership_prompt','founder_mode','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (195, 'The hottest love has the coldest end.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','resilience','truth'], 'reflection', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (196, 'Allegiance to the right and to the true is loyalty to the state.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Crito', 'medium', ARRAY['ethics','virtue','truth'], 'leadership', 'stoic', ARRAY['leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (197, 'The children now love luxury; they have bad manners, contempt for authority; they show disrespect for elders and love chatter in place of exercise.', 'The children now love luxury and show disrespect for elders.', 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['discipline','virtue','ethics'], 'reflection', 'reflective', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (198, 'Wisdom begins in wonder.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Theaetetus', 'medium', ARRAY['learning','philosophy','humility'], 'philosophy', 'visionary', ARRAY['onboarding','study_motivation','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (199, 'The greatest way to live with honour in this world is to be what we pretend to be.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['virtue','excellence','ethics'], 'excellence', 'disciplined', ARRAY['dashboard_daily_quote','leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (200, 'I pray thee, O God, that I may be beautiful within.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Phaedrus', 'high', ARRAY['virtue','humility','philosophy'], 'reflection', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (201, 'One thing only I know, and that is that I know nothing.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['humility','philosophy','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (202, 'Do not do to others what angers you if done to you by others.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['ethics','virtue','service'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (203, 'Beware the barrenness of a busy life.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','focus','discipline'], 'reflection', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (204, 'From the deepest desires often come the deadliest hate.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Republic', 'medium', ARRAY['philosophy','truth','resilience'], 'reflection', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (205, 'Thou shouldst eat to live; not live to eat.', NULL, 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'medium', ARRAY['discipline','virtue','focus'], 'surgeon_mindset', 'disciplined', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (206, 'The unexamined life is not worth living for a human being.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['philosophy','truth','humility'], 'reflection', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (207, 'Prefer knowledge to wealth, for the one is transitory, the other perpetual.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','philosophy','truth'], 'philosophy', 'visionary', ARRAY['study_motivation','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (208, 'The mind is everything; what you think you become.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','focus','mastery'], 'surgeon_mindset', 'visionary', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (209, 'Not life, but good life, is to be chiefly valued.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Crito', 'high', ARRAY['virtue','excellence','philosophy'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (210, 'If a man is proud of his wealth, he should not be praised until it is known how he employs it.', 'A man should not be praised for wealth until it is known how he employs it.', 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['ethics','virtue','leadership'], 'leadership', 'disciplined', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (211, 'Envy is the ulcer of the soul.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['virtue','philosophy','resilience'], 'reflection', 'stoic', ARRAY['dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (212, 'He is richest who is content with the least, for contentment is the wealth of nature.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['humility','virtue','discipline'], 'reflection', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (213, 'To be is to do.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['excellence','discipline','mastery'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (214, 'When the debate is lost, slander becomes the tool of the loser.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['truth','courage','ethics'], 'leadership', 'stoic', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (215, 'Understanding a question is half an answer.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','philosophy','mastery'], 'teaching', 'calm', ARRAY['teaching_rounds','study_motivation','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (216, 'In every one of us there are two ruling and directing principles, whose guidance we follow wherever they may lead; the one being an innate desire of pleasure; the other, an acquired judgment which aspires after excellence.', 'In us all are two principles: innate desire for pleasure, and acquired judgment aspiring to excellence.', 'Socrates', 'c. 470–399 BC', 'Plato, Phaedrus', 'high', ARRAY['discipline','excellence','philosophy'], 'surgeon_mindset', 'reflective', ARRAY['post_op_reflection','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (217, 'No one can teach, if by teaching we mean the transmission of knowledge, in any mechanical fashion, from one person to another. The most that can be done is that one person who is more knowledgeable than another can, by asking a series of questions, stimulate the other to think.', 'No one transmits knowledge mechanically; the best teaching stimulates thought.', 'Socrates', 'c. 470–399 BC', 'Plato, Meno', 'medium', ARRAY['learning','philosophy','humility'], 'teaching', 'reflective', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (218, 'We cannot live better than in seeking to become better.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['excellence','mastery','discipline'], 'excellence', 'relentless', ARRAY['study_motivation','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (219, 'Every action has its pleasures and its price.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['discipline','truth','philosophy'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (220, 'I am not an Athenian or a Greek, but a citizen of the world.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['philosophy','service','humility'], 'philosophy', 'visionary', ARRAY['onboarding','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (221, 'It is not living that matters, but living rightly.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Crito', 'high', ARRAY['virtue','ethics','excellence'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (222, 'The hour of departure has arrived, and we go our separate ways, I to die, and you to live. Which of these two is better only God knows.', 'I go to die, and you to live. Which is better only God knows.', 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['courage','philosophy','resilience'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (223, 'No one desires evil. For what is evil but the perception of the ignorant?', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Meno', 'medium', ARRAY['philosophy','truth','ethics'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (224, 'The only good is knowledge and the only evil is ignorance.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','truth','philosophy'], 'philosophy', 'stoic', ARRAY['study_motivation','teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (225, 'Those who are hardest to love need it the most.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['service','ethics','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (226, 'Regard your good name as the richest jewel you can possibly be possessed of.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['virtue','excellence','ethics'], 'excellence', 'disciplined', ARRAY['leadership_prompt','onboarding','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (227, 'All men''s souls are immortal, but the souls of the righteous are immortal and divine.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Phaedo', 'medium', ARRAY['virtue','philosophy','courage'], 'philosophy', 'visionary', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (228, 'Worthless people live only to eat and drink; people of worth eat and drink only to live.', NULL, 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'medium', ARRAY['discipline','virtue','focus'], 'surgeon_mindset', 'disciplined', ARRAY['dashboard_daily_quote','pre_op_mindset'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (229, 'The beginning of wisdom is the definition of terms.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['learning','truth','mastery'], 'teaching', 'disciplined', ARRAY['teaching_rounds','study_motivation','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (230, 'If you don''t get what you want, you suffer; if you get what you don''t want, you suffer; even when you get exactly what you want, you still suffer because you can''t hold on to it forever.', 'Whether you get what you want or not, you suffer; nothing lasts forever.', 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['resilience','philosophy','truth'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (231, 'Be as you wish to seem.', NULL, 'Socrates', 'c. 470–399 BC', 'Xenophon, Memorabilia', 'medium', ARRAY['virtue','excellence','ethics'], 'excellence', 'elite', ARRAY['pre_op_mindset','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (232, 'The easiest and noblest way is not to be crushing others, but to be improving yourselves.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['excellence','humility','leadership'], 'leadership', 'calm', ARRAY['leadership_prompt','teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (233, 'I was really too honest a man to be a politician and live.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['truth','courage','ethics'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (234, 'Sometimes you put walls up not to keep people out, but to see who cares enough to break them down.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['resilience','truth','courage'], 'resilience', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (235, 'It is better to change an opinion than to persist in a wrong one.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['truth','humility','courage'], 'clinical_wisdom', 'calm', ARRAY['teaching_rounds','post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (236, 'Be nicer than necessary to everyone you meet. Everyone is fighting some kind of battle.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'low', ARRAY['service','ethics','humility'], 'patient_care', 'compassionate', ARRAY['dashboard_daily_quote','share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (237, 'The soul takes nothing with her to the next world but her education and culture.', NULL, 'Socrates', 'c. 470–399 BC', 'Plato, Phaedo', 'high', ARRAY['learning','philosophy','excellence'], 'philosophy', 'reflective', ARRAY['study_motivation','post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (238, 'Falling down is not a failure. Failure comes when you stay where you have fallen.', NULL, 'Socrates', 'c. 470–399 BC', NULL, 'medium', ARRAY['resilience','courage','discipline'], 'resilience', 'relentless', ARRAY['post_op_reflection','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (239, 'To fear death, gentlemen, is no other than to think oneself wise when one is not, to think one knows what one does not know.', 'To fear death is to think oneself wise when one is not.', 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['courage','philosophy','truth'], 'philosophy', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (240, 'Are you not ashamed of heaping up the greatest amount of money and honour and reputation, and caring so little about wisdom and truth and the greatest improvement of the soul?', 'Are you not ashamed of caring for money and reputation but not wisdom and the soul?', 'Socrates', 'c. 470–399 BC', 'Plato, Apology', 'high', ARRAY['virtue','truth','philosophy'], 'philosophy', 'relentless', ARRAY['dashboard_daily_quote','leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (241, 'Courage is knowing what not to fear.', NULL, 'Plato', 'c. 428–348 BC', 'Protagoras', 'high', ARRAY['courage','philosophy','truth'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (242, 'The measure of a man is what he does with power.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['leadership','ethics','virtue'], 'leadership', 'elite', ARRAY['leadership_prompt','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (243, 'We can easily forgive a child who is afraid of the dark; the real tragedy of life is when men are afraid of the light.', 'The real tragedy of life is when men are afraid of the light.', 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['courage','truth','philosophy'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (244, 'The greatest wealth is to live content with little.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['virtue','humility','discipline'], 'reflection', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (245, 'Ignorance, the root and stem of every evil.', NULL, 'Plato', 'c. 428–348 BC', 'Phaedrus', 'high', ARRAY['learning','truth','philosophy'], 'teaching', 'stoic', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (246, 'Good actions give strength to ourselves and inspire good actions in others.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'medium', ARRAY['virtue','leadership','service'], 'leadership', 'visionary', ARRAY['leadership_prompt','teaching_rounds','share_card'], true);
