INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (252, 'The soul takes nothing with her to the next world but her education and culture.', NULL, 'Plato', 'c. 428–348 BC', 'Phaedo', 'high', ARRAY['learning','philosophy','truth'], 'teaching', 'reflective', ARRAY['study_motivation','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (253, 'He who commits injustice is ever made more wretched than he who suffers it.', NULL, 'Plato', 'c. 428–348 BC', 'Gorgias', 'high', ARRAY['ethics','virtue','truth'], 'philosophy', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (254, 'An unexamined life is not worth living.', NULL, 'Plato', 'c. 428–348 BC', 'Apology', 'high', ARRAY['philosophy','truth','learning'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (255, 'Allegiance to the truth is the foundation of justice.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['truth','ethics','virtue'], 'philosophy', 'stoic', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (256, 'No one is more hated than he who speaks the truth.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['truth','courage','resilience'], 'resilience', 'stoic', ARRAY['dashboard_daily_quote','share_card'], true);
