INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (259, 'The mind is everything; what you think, you become.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'low', ARRAY['discipline','mastery','focus'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','push_notification'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (260, 'I am the wisest man alive, for I know one thing, and that is that I know nothing.', 'I know one thing, and that is that I know nothing.', 'Plato', 'c. 428–348 BC', 'Apology', 'high', ARRAY['humility','learning','philosophy'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (261, 'Love is a serious mental disease.', NULL, 'Plato', 'c. 428–348 BC', 'Phaedrus', 'high', ARRAY['philosophy','truth'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (262, 'At the touch of love everyone becomes a poet.', NULL, 'Plato', 'c. 428–348 BC', 'Symposium', 'high', ARRAY['philosophy','excellence'], 'reflection', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (263, 'One of the penalties for refusing to participate in politics is that you end up being governed by your inferiors.', 'Refuse to participate in politics and you end up governed by your inferiors.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['leadership','ethics','courage'], 'leadership', 'elite', ARRAY['leadership_prompt','founder_mode','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (264, 'There are three classes of men: lovers of wisdom, lovers of honor, and lovers of gain.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['philosophy','virtue','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (265, 'No man should bring children into the world who is unwilling to persevere to the end in their nature and education.', 'No man should bring children into the world unwilling to persevere in their education.', 'Plato', 'c. 428–348 BC', 'Crito', 'medium', ARRAY['discipline','learning','service'], 'teaching', 'disciplined', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (266, 'Attention to health is life''s greatest hindrance.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['philosophy','discipline','focus'], 'reflection', 'stoic', ARRAY['dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (267, 'The direction in which education starts a man will determine his future in life.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['learning','excellence','discipline'], 'teaching', 'visionary', ARRAY['onboarding','study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (268, 'Excess of liberty, whether it lies in state or individuals, seems only to pass into excess of slavery.', 'Excess of liberty seems only to pass into excess of slavery.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['discipline','philosophy','leadership'], 'philosophy', 'stoic', ARRAY['leadership_prompt','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (269, 'Only the dead have seen the end of war.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'low', ARRAY['resilience','courage','truth'], 'resilience', 'stoic', ARRAY['dashboard_daily_quote','share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (270, 'Justice in the life and conduct of the state is possible only as first it resides in the hearts and souls of the citizens.', 'Justice in the state is possible only as it first resides in the souls of citizens.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['ethics','virtue','leadership'], 'leadership', 'visionary', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (271, 'Thinking is the talking of the soul with itself.', NULL, 'Plato', 'c. 428–348 BC', 'Theaetetus', 'high', ARRAY['philosophy','truth','learning'], 'reflection', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (272, 'Knowledge without justice ought to be called cunning rather than wisdom.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['ethics','truth','virtue'], 'clinical_wisdom', 'stoic', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (273, 'Allegiance to truth is the essence of philosophy.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['truth','philosophy'], 'philosophy', 'reflective', ARRAY['study_motivation','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (274, 'No law or ordinance is mightier than understanding.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['learning','truth','leadership'], 'philosophy', 'visionary', ARRAY['leadership_prompt','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (275, 'Music is a moral law. It gives soul to the universe, wings to the mind, flight to the imagination, and charm and gaiety to life and to everything.', 'Music gives soul to the universe, wings to the mind, flight to the imagination.', 'Plato', 'c. 428–348 BC', NULL, 'low', ARRAY['excellence','philosophy'], 'reflection', 'visionary', ARRAY['dashboard_daily_quote','share_card'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (276, 'Bodily exercise, when compulsory, does no harm to the body; but knowledge which is acquired under compulsion obtains no hold on the mind.', 'Knowledge acquired under compulsion obtains no hold on the mind.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['learning','discipline','mastery'], 'teaching', 'reflective', ARRAY['study_motivation','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (277, 'The greatest penalty of evildoing is to grow into the likeness of bad men.', NULL, 'Plato', 'c. 428–348 BC', 'Theaetetus', 'high', ARRAY['ethics','virtue','truth'], 'philosophy', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (278, 'He who is of a calm and happy nature will hardly feel the pressure of age, but to him who is of an opposite disposition youth and age are equally a burden.', 'He who is of a calm nature will hardly feel the pressure of age.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['resilience','virtue','discipline'], 'resilience', 'calm', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (279, 'The heaviest penalty for declining to rule is to be ruled by someone inferior to yourself.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['leadership','courage','excellence'], 'leadership', 'elite', ARRAY['leadership_prompt','founder_mode'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (280, 'Let parents bequeath to their children not riches, but the spirit of reverence.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['virtue','humility','service'], 'teaching', 'compassionate', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (281, 'The object of education is to teach us to love what is beautiful.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['learning','excellence','philosophy'], 'teaching', 'visionary', ARRAY['onboarding','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (282, 'Do not train a child to learn by force or harshness; but direct them to it by what amuses their minds.', 'Direct children to learning by what amuses their minds.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['learning','service','leadership'], 'teaching', 'compassionate', ARRAY['teaching_rounds','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (283, 'He was a wise man who invented beer.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'low', ARRAY['philosophy','humility'], 'reflection', 'calm', ARRAY['dashboard_daily_quote'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (284, 'Rhetoric is the art of ruling the minds of men.', NULL, 'Plato', 'c. 428–348 BC', 'Phaedrus', 'high', ARRAY['leadership','mastery','focus'], 'leadership', 'elite', ARRAY['leadership_prompt','founder_mode'], true);
