INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (286, 'States are as the men are; they grow out of human characters.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['leadership','virtue','ethics'], 'leadership', 'reflective', ARRAY['leadership_prompt','founder_mode'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (287, 'Allegiance to the truth leads to a good and beautiful life.', NULL, 'Plato', 'c. 428–348 BC', 'Philebus', 'medium', ARRAY['truth','virtue','excellence'], 'philosophy', 'calm', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (288, 'Nothing in the affairs of men is worthy of great anxiety.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['resilience','humility','philosophy'], 'resilience', 'stoic', ARRAY['pre_op_mindset','post_op_reflection','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (289, 'A hero is born among a hundred, a wise man is found among a thousand, but an accomplished one might not be found even among a hundred thousand men.', 'A hero is born among a hundred, a wise man among a thousand.', 'Plato', 'c. 428–348 BC', NULL, 'medium', ARRAY['excellence','mastery','humility'], 'excellence', 'elite', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (290, 'There is in every one of us, even those who seem to be most moderate, a type of desire that is terrible, wild, and lawless.', 'In every one of us is a type of desire that is terrible, wild, and lawless.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['discipline','truth','philosophy'], 'reflection', 'reflective', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (291, 'The madness of love is the greatest of heaven''s blessings.', NULL, 'Plato', 'c. 428–348 BC', 'Phaedrus', 'high', ARRAY['philosophy','courage'], 'reflection', 'visionary', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (292, 'Wonder is the feeling of a philosopher, and philosophy begins in wonder.', NULL, 'Plato', 'c. 428–348 BC', 'Theaetetus', 'high', ARRAY['philosophy','learning','truth'], 'philosophy', 'visionary', ARRAY['onboarding','study_motivation','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (293, 'The penalty good men pay for indifference to public affairs is to be ruled by evil men.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['leadership','courage','ethics'], 'leadership', 'stoic', ARRAY['leadership_prompt','founder_mode'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (294, 'You can discover more about a person in an hour of play than in a year of conversation.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'low', ARRAY['truth','learning','humility'], 'clinical_wisdom', 'calm', ARRAY['teaching_rounds','dashboard_daily_quote'], false);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (295, 'Those who tell the stories rule society.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'medium', ARRAY['leadership','truth','mastery'], 'founder_vision', 'elite', ARRAY['founder_mode','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (296, 'If a man neglects education, he walks lame to the end of his life.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['learning','discipline','excellence'], 'teaching', 'disciplined', ARRAY['study_motivation','teaching_rounds','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (297, 'No human thing is of serious importance.', NULL, 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['humility','philosophy','resilience'], 'reflection', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (298, 'There must always remain something that is antagonistic to good.', NULL, 'Plato', 'c. 428–348 BC', 'Theaetetus', 'high', ARRAY['resilience','truth','philosophy'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (299, 'For a man to conquer himself is the first and noblest of all victories.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['discipline','mastery','courage'], 'surgeon_mindset', 'relentless', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (300, 'The life which is unexamined is not worth living.', NULL, 'Plato', 'c. 428–348 BC', 'Apology', 'high', ARRAY['philosophy','truth','learning'], 'reflection', 'reflective', ARRAY['post_op_reflection','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (301, 'All learning has an emotional base.', NULL, 'Plato', 'c. 428–348 BC', NULL, 'medium', ARRAY['learning','philosophy'], 'teaching', 'calm', ARRAY['teaching_rounds','study_motivation'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (302, 'Virtue is the health and beauty and well-being of the soul; vice is the disease and weakness and deformity of the soul.', 'Virtue is the health of the soul; vice is its disease.', 'Plato', 'c. 428–348 BC', 'Republic', 'high', ARRAY['virtue','medicine','ethics'], 'clinical_wisdom', 'reflective', ARRAY['teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (303, 'Lack of activity destroys the good condition of every human being, while movement and methodical physical exercise save it and preserve it.', 'Lack of activity destroys good condition; exercise saves and preserves it.', 'Plato', 'c. 428–348 BC', 'Timaeus', 'high', ARRAY['discipline','medicine','excellence'], 'clinical_wisdom', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (304, 'The community which has neither poverty nor riches will always have the noblest principles.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['ethics','virtue','leadership'], 'philosophy', 'visionary', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (305, 'No wealth can ever make a bad man at peace with himself.', NULL, 'Plato', 'c. 428–348 BC', 'Laws', 'high', ARRAY['virtue','truth','ethics'], 'reflection', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (306, 'It is the mark of an educated mind to be able to entertain a thought without accepting it.', NULL, 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'medium', ARRAY['philosophy','learning','truth'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (307, 'Knowing yourself is the beginning of all wisdom.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['philosophy','truth','humility'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (308, 'Pleasure in the job puts perfection in the work.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['excellence','mastery','discipline'], 'excellence', 'elite', ARRAY['dashboard_daily_quote','pre_op_mindset','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (309, 'The roots of education are bitter, but the fruit is sweet.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['learning','resilience','discipline'], 'teaching', 'disciplined', ARRAY['study_motivation','teaching_rounds','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (310, 'Excellence is never an accident. It is always the result of high intention, sincere effort, and intelligent execution.', 'Excellence is the result of high intention, sincere effort, and intelligent execution.', 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['excellence','discipline','mastery'], 'excellence', 'elite', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (311, 'Patience is bitter, but its fruit is sweet.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['resilience','discipline','virtue'], 'resilience', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (312, 'The whole is greater than the sum of its parts.', NULL, 'Aristotle', '384–322 BC', 'Metaphysics', 'high', ARRAY['philosophy','leadership','truth'], 'philosophy', 'visionary', ARRAY['leadership_prompt','dashboard_daily_quote','share_card'], true);
