INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (315, 'The energy of the mind is the essence of life.', NULL, 'Aristotle', '384–322 BC', 'On the Soul', 'medium', ARRAY['philosophy','focus','mastery'], 'surgeon_mindset', 'elite', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (316, 'The educated differ from the uneducated as much as the living from the dead.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['learning','excellence','truth'], 'teaching', 'elite', ARRAY['study_motivation','teaching_rounds','share_card'], true);
