INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (318, 'The aim of art is to represent not the outward appearance of things, but their inward significance.', 'Art aims to represent not outward appearance, but inward significance.', 'Aristotle', '384–322 BC', 'Poetics', 'medium', ARRAY['mastery','truth','philosophy'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (319, 'The soul never thinks without a picture.', NULL, 'Aristotle', '384–322 BC', 'On the Soul', 'high', ARRAY['philosophy','truth','learning'], 'reflection', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (320, 'Quality is not an act, it is a habit.', NULL, 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'medium', ARRAY['excellence','discipline','mastery'], 'excellence', 'disciplined', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (321, 'The more you know, the more you realize you don''t know.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['humility','learning','philosophy'], 'teaching', 'reflective', ARRAY['study_motivation','post_op_reflection','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (322, 'Courage is the first of human qualities because it is the quality which guarantees the others.', 'Courage is the first of human qualities because it guarantees the others.', 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['courage','virtue','excellence'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (323, 'Those who educate children well are more to be honored than they who produce them.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['learning','service','leadership'], 'teaching', 'compassionate', ARRAY['teaching_rounds','leadership_prompt','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (324, 'No great mind has ever existed without a touch of madness.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['excellence','courage','philosophy'], 'surgeon_mindset', 'elite', ARRAY['dashboard_daily_quote','share_card','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (325, 'Man is by nature a political animal.', NULL, 'Aristotle', '384–322 BC', 'Politics', 'high', ARRAY['philosophy','leadership','truth'], 'philosophy', 'calm', ARRAY['dashboard_daily_quote','leadership_prompt'], true);
