INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (328, 'Happiness is the meaning and the purpose of life, the whole aim and end of human existence.', 'Happiness is the meaning and purpose of life.', 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['philosophy','virtue','truth'], 'philosophy', 'visionary', ARRAY['dashboard_daily_quote','post_op_reflection','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (329, 'He who has overcome his fears will truly be free.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['courage','resilience','philosophy'], 'resilience', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote','push_notification'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (330, 'The virtue of justice consists in moderation, as regulated by wisdom.', NULL, 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['ethics','virtue','philosophy'], 'philosophy', 'calm', ARRAY['dashboard_daily_quote','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (331, 'All human actions have one or more of these seven causes: chance, nature, compulsion, habit, reason, passion, and desire.', 'All human actions stem from chance, nature, compulsion, habit, reason, passion, or desire.', 'Aristotle', '384–322 BC', 'Rhetoric', 'high', ARRAY['philosophy','truth','ethics'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
