INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (333, 'The worst form of inequality is to try to make unequal things equal.', NULL, 'Aristotle', '384–322 BC', 'Politics', 'medium', ARRAY['truth','ethics','philosophy'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (334, 'The antidote for fifty enemies is one friend.', NULL, 'Aristotle', '384–322 BC', 'Eudemian Ethics', 'medium', ARRAY['virtue','resilience','service'], 'reflection', 'compassionate', ARRAY['dashboard_daily_quote','share_card'], true);
