INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (339, 'Hope is a waking dream.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['resilience','philosophy','courage'], 'reflection', 'visionary', ARRAY['dashboard_daily_quote','push_notification','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (340, 'For the things we have to learn before we can do them, we learn by doing them.', NULL, 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['learning','mastery','discipline'], 'teaching', 'disciplined', ARRAY['study_motivation','teaching_rounds','onboarding'], true);
