INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (346, 'Fear is pain arising from the anticipation of evil.', NULL, 'Aristotle', '384–322 BC', 'Rhetoric', 'high', ARRAY['courage','philosophy','resilience'], 'surgeon_mindset', 'stoic', ARRAY['pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (347, 'Poverty is the parent of revolution and crime.', NULL, 'Aristotle', '384–322 BC', 'Politics', 'high', ARRAY['ethics','truth','leadership'], 'philosophy', 'reflective', ARRAY['dashboard_daily_quote','leadership_prompt'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (348, 'Youth is easily deceived because it is quick to hope.', NULL, 'Aristotle', '384–322 BC', 'Rhetoric', 'high', ARRAY['humility','learning','truth'], 'teaching', 'reflective', ARRAY['teaching_rounds','post_op_reflection'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (349, 'The aim of the wise is not to secure pleasure, but to avoid pain.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['philosophy','discipline','truth'], 'philosophy', 'stoic', ARRAY['dashboard_daily_quote','post_op_reflection'], true);
