INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (351, 'A great city is not to be confounded with a populous one.', NULL, 'Aristotle', '384–322 BC', 'Politics', 'high', ARRAY['leadership','excellence','truth'], 'leadership', 'calm', ARRAY['leadership_prompt','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (352, 'The least initial deviation from the truth is multiplied later a thousandfold.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['truth','ethics','discipline'], 'clinical_wisdom', 'disciplined', ARRAY['pre_op_mindset','teaching_rounds','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (353, 'Those that know, do. Those that understand, teach.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['learning','mastery','leadership'], 'teaching', 'elite', ARRAY['teaching_rounds','study_motivation','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (354, 'Persuasion is achieved by the speaker''s personal character when the speech is so spoken as to make us think him credible.', 'Persuasion is achieved when the speaker''s character makes us think him credible.', 'Aristotle', '384–322 BC', 'Rhetoric', 'high', ARRAY['leadership','truth','ethics'], 'leadership', 'calm', ARRAY['leadership_prompt','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (355, 'Moral excellence comes about as a result of habit. We become just by doing just acts, temperate by doing temperate acts, brave by doing brave acts.', 'We become just by doing just acts, brave by doing brave acts.', 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['virtue','discipline','mastery'], 'excellence', 'disciplined', ARRAY['study_motivation','pre_op_mindset','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (356, 'Anybody can become angry — that is easy, but to be angry with the right person and to the right degree and at the right time and for the right purpose, and in the right way — that is not within everybody''s power and is not easy.', 'To be angry with the right person, to the right degree, at the right time — that is not easy.', 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'high', ARRAY['discipline','virtue','ethics'], 'surgeon_mindset', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote','share_card'], true);
