INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (358, 'Well begun is half done.', NULL, 'Aristotle', '384–322 BC', 'Politics', 'high', ARRAY['discipline','focus','excellence'], 'surgeon_mindset', 'disciplined', ARRAY['pre_op_mindset','push_notification','onboarding'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (359, 'The secret to humor is surprise.', NULL, 'Aristotle', '384–322 BC', 'Rhetoric', 'medium', ARRAY['truth','philosophy','learning'], 'reflection', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (360, 'Good habits formed at youth make all the difference.', NULL, 'Aristotle', '384–322 BC', 'Nicomachean Ethics', 'medium', ARRAY['discipline','learning','mastery'], 'teaching', 'disciplined', ARRAY['study_motivation','onboarding','teaching_rounds'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (361, 'The gods too are fond of a joke.', NULL, 'Aristotle', '384–322 BC', 'Eudemian Ethics', 'medium', ARRAY['humility','philosophy','truth'], 'reflection', 'calm', ARRAY['dashboard_daily_quote','share_card'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (362, 'To perceive is to suffer.', NULL, 'Aristotle', '384–322 BC', 'On the Soul', 'medium', ARRAY['philosophy','resilience','truth'], 'reflection', 'stoic', ARRAY['post_op_reflection','dashboard_daily_quote'], true);
INSERT INTO "Quote" (id, quote, short_quote, author, era, source, source_confidence, themes, category, mood, use_case, is_verified) VALUES (363, 'Educating the mind without educating the heart is no education at all.', NULL, 'Aristotle', '384–322 BC', NULL, 'medium', ARRAY['learning','ethics','service'], 'teaching', 'compassionate', ARRAY['teaching_rounds','study_motivation','share_card'], true);
